// -*- coding: utf-8 -*-
#include <iostream>
#include <queue>
using namespace std;

class Solution {
public:
bool solveMinPriorityQueue(int n, const vector<int>& items, int k) {
    priority_queue<int> heap;
    for (int i = 0; i < n; i++) {
        if (items[i] >= k) {
            if (!heap.empty()) {
                heap.pop();
            }
            heap.push(items[i]);
        }
    }
    return !heap.empty();
}
};

int main() {
    int n, k;
    cin >> n >> k;
    vector<int> items(n);
    for (int i = 0; i < n; i++) {
        cin >> items[i];
    }
    Solution solution;
    for (int i = 0; i < n; i++) {
        cout << solution.solveMinPriorityQueue(n, items, k) << endl;
        k++;
    }
    return 0;
}
